import{c as t,S as a,j as h,m as i}from"./chunks/framework.8aa1YH_s.js";const m=JSON.parse('{"title":"Kiểm tra đầu vào","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/kiem-tra-dau-vao.md","filePath":"hoc-vien/kiem-tra-dau-vao.md","lastUpdated":0}'),o={name:"hoc-vien/kiem-tra-dau-vao.md"};function r(l,n,c,e,g,u){return a(),h("div",null,[...n[0]||(n[0]=[i('<h1 id="kiem-tra-đau-vao" tabindex="-1">Kiểm tra đầu vào <a class="header-anchor" href="#kiem-tra-đau-vao" aria-label="Permalink to “Kiểm tra đầu vào”">​</a></h1><p><strong>Mục đích:</strong> Đánh giá <strong>trình độ hiện tại</strong> của bạn trước khi bắt đầu một khóa học hoặc lộ trình ôn thi.</p><h2 id="khi-nao-ban-nen-lam-bai-kiem-tra-đau-vao" tabindex="-1">Khi nào bạn nên làm bài kiểm tra đầu vào? <a class="header-anchor" href="#khi-nao-ban-nen-lam-bai-kiem-tra-đau-vao" aria-label="Permalink to “Khi nào bạn nên làm bài kiểm tra đầu vào?”">​</a></h2><ul><li>Bạn <strong>mới đăng ký</strong> vào khóa luyện thi HSA/TSA/THPT.</li><li>Bạn không chắc trình độ của mình - cần biết nên bắt đầu từ chuyên đề nào.</li><li>Trung tâm yêu cầu kiểm tra đầu vào để <strong>phân lớp</strong> (lớp cơ bản / nâng cao).</li><li>Bạn muốn <strong>so sánh trước-sau</strong> một giai đoạn ôn luyện.</li></ul><h2 id="tim-bai-kiem-tra-đau-vao-o-đau" tabindex="-1">Tìm bài kiểm tra đầu vào ở đâu? <a class="header-anchor" href="#tim-bai-kiem-tra-đau-vao-o-đau" aria-label="Permalink to “Tìm bài kiểm tra đầu vào ở đâu?”">​</a></h2><h3 id="cach-1-tu-trang-chu" tabindex="-1">Cách 1: Từ trang chủ <a class="header-anchor" href="#cach-1-tu-trang-chu" aria-label="Permalink to “Cách 1: Từ trang chủ”">​</a></h3><ul><li>Trên trang chủ, có khu vực <strong>&quot;Kiểm tra đầu vào miễn phí&quot;</strong>.</li><li>Bấm để chọn môn / khóa.</li></ul><h3 id="cach-2-trong-khoa-hoc-cua-ban" tabindex="-1">Cách 2: Trong khóa học của bạn <a class="header-anchor" href="#cach-2-trong-khoa-hoc-cua-ban" aria-label="Permalink to “Cách 2: Trong khóa học của bạn”">​</a></h3><ul><li>Vào <strong>Khóa học của tôi</strong> → mở khóa.</li><li>Bài kiểm tra đầu vào thường ở <strong>đầu cây nội dung</strong> (chương 0 / mục đặc biệt).</li></ul><h3 id="cach-3-theo-loai-chuong-trinh" tabindex="-1">Cách 3: Theo loại chương trình <a class="header-anchor" href="#cach-3-theo-loai-chuong-trinh" aria-label="Permalink to “Cách 3: Theo loại chương trình”">​</a></h3><ul><li>Vào menu <strong>Theo loại</strong> → <strong>Kiểm tra đầu vào</strong>.</li></ul><h2 id="đac-điem" tabindex="-1">Đặc điểm <a class="header-anchor" href="#đac-điem" aria-label="Permalink to “Đặc điểm”">​</a></h2><ul><li><strong>Đề ngắn</strong>: thường 15-45 phút, 15-30 câu.</li><li><strong>Tập trung kiến thức nền tảng</strong> của môn / kỳ thi.</li><li><strong>Có thể được giáo viên cho làm lại</strong> (1-3 lần).</li><li><strong>Không tính vào điểm tổng</strong> của khóa - chỉ để đánh giá.</li></ul><h2 id="quy-trinh-lam-bai" tabindex="-1">Quy trình làm bài <a class="header-anchor" href="#quy-trinh-lam-bai" aria-label="Permalink to “Quy trình làm bài”">​</a></h2><ol><li>Vào trang xem trước → đọc kỹ: <ul><li>Số câu, thời gian.</li><li>Phạm vi kiến thức.</li></ul></li><li>Bấm <strong>Bắt đầu</strong>.</li><li>Làm bài như <a href="./luyen-tap">Luyện tập thông thường</a>.</li><li>Nộp bài.</li></ol><h2 id="ket-qua-phan-loai-trinh-đo" tabindex="-1">Kết quả &amp; Phân loại trình độ <a class="header-anchor" href="#ket-qua-phan-loai-trinh-đo" aria-label="Permalink to “Kết quả &amp; Phân loại trình độ”">​</a></h2><p>Sau khi nộp, hệ thống hiển thị:</p><h3 id="tong-điem" tabindex="-1">Tổng điểm <a class="header-anchor" href="#tong-điem" aria-label="Permalink to “Tổng điểm”">​</a></h3><ul><li>Vd 7.5/10 → &quot;Trung bình - Khá&quot;.</li></ul><h3 id="phan-loai" tabindex="-1">Phân loại <a class="header-anchor" href="#phan-loai" aria-label="Permalink to “Phân loại”">​</a></h3><p>Hệ thống thường chia thành các mức:</p><ul><li><strong>Yếu</strong> (&lt; 4 điểm): cần học từ đầu, nắm chắc nền tảng.</li><li><strong>Trung bình</strong> (4-6): có kiến thức cơ bản, cần củng cố.</li><li><strong>Khá</strong> (6-8): nắm vững nền, có thể đi sâu chuyên đề.</li><li><strong>Giỏi</strong> (8-10): đã sẵn sàng làm đề thực chiến.</li></ul><h3 id="goi-y-lo-trinh" tabindex="-1">Gợi ý lộ trình <a class="header-anchor" href="#goi-y-lo-trinh" aria-label="Permalink to “Gợi ý lộ trình”">​</a></h3><p>Hệ thống có thể gợi ý:</p><ul><li>&quot;Bạn nên bắt đầu từ Chương X&quot; (tương ứng trình độ).</li><li>&quot;Bạn còn yếu ở chủ đề Y - nên ôn thêm&quot;.</li><li>&quot;Lời khuyên: dành Z giờ/tuần học&quot;.</li></ul><h3 id="phan-tich-theo-chu-đe" tabindex="-1">Phân tích theo chủ đề <a class="header-anchor" href="#phan-tich-theo-chu-đe" aria-label="Permalink to “Phân tích theo chủ đề”">​</a></h3><p>Bảng / biểu đồ cho biết bạn <strong>mạnh ở đâu, yếu ở đâu</strong>:</p><table tabindex="0"><thead><tr><th>Chủ đề</th><th>Câu đúng / Tổng</th><th>Tỷ lệ</th></tr></thead><tbody><tr><td>Hàm số bậc 2</td><td>4/5</td><td>80%</td></tr><tr><td>Lượng giác</td><td>1/5</td><td>20% (Yếu)</td></tr><tr><td>...</td><td></td><td></td></tr></tbody></table><h2 id="su-dung-ket-qua" tabindex="-1">Sử dụng kết quả <a class="header-anchor" href="#su-dung-ket-qua" aria-label="Permalink to “Sử dụng kết quả”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Đọc kỹ phân tích theo chủ đề</p><p>Đừng chỉ nhìn tổng điểm. Phần &quot;yếu&quot; cho bạn biết <strong>mục tiêu ôn cần tập trung</strong>.</p></div><div class="tip custom-block"><p class="custom-block-title">Lưu kết quả để so sánh sau</p><p>Sau 1-2 tháng ôn luyện, làm lại 1 đề tương tự để xem <strong>mức tăng</strong>. Đây là cách đánh giá khách quan.</p></div><div class="tip custom-block"><p class="custom-block-title">Kết quả không phản ánh &quot;thông minh&quot;</p><p>Đây chỉ là <strong>ảnh chụp tại 1 thời điểm</strong>. Cố gắng &amp; lộ trình đúng sẽ cải thiện nhanh.</p></div><h2 id="lam-lai-bai-kiem-tra-đau-vao" tabindex="-1">Làm lại bài kiểm tra đầu vào <a class="header-anchor" href="#lam-lai-bai-kiem-tra-đau-vao" aria-label="Permalink to “Làm lại bài kiểm tra đầu vào”">​</a></h2><ul><li>Nếu được phép, bấm <strong>Làm lại</strong> ở trang xem trước.</li><li>Số lần làm lại thường giới hạn (vd: 1-3 lần).</li><li>Sau khi làm lại, hệ thống cập nhật phân loại mới.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi điểm cao có được &quot;nhảy&quot; sang khóa nâng cao không?</strong> → Tùy trung tâm. Liên hệ giáo viên để được tư vấn lộ trình phù hợp.</p><p><strong>Tôi điểm thấp có nên buồn không?</strong> → Không nên. Đây là <strong>điểm xuất phát</strong>. Nếu điểm thấp, bạn càng có <strong>nhiều room để tiến bộ</strong> và cảm nhận rõ kết quả khi học.</p><p><strong>Bài kiểm tra đầu vào có khác bài thi thử ĐGNL/THPT không?</strong> → Có. Bài kiểm tra đầu vào <strong>ngắn hơn</strong>, <strong>dễ hơn</strong>, chỉ kiểm tra nền tảng. Còn thi thử là mô phỏng kỳ thi thật.</p><p><strong>Tôi đã làm rồi nhưng không thấy kết quả phân loại?</strong> → Có thể hệ thống chưa cấu hình ngưỡng phân loại cho đề đó. Liên hệ giáo viên.</p>',39)])])}const d=t(o,[["render",r]]);export{m as __pageData,d as default};
